package com.google.gson;
import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.Gson;
import com.google.gson.JsonIOException;
import com.google.gson.JsonSyntaxException;
import com.google.gson.internal.Primitives;
import com.google.gson.reflect.TypeToken;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

import java.io.Reader;
import java.io.StringReader;

class GsonFromJsonTest {

  private Gson gson;

  @BeforeEach
  void setUp() {
    gson = new Gson();
  }

  @Test
  void fromJson_withValidJson_returnsObject() throws Exception {
    String json = "{\"field\":\"value\"}";
    Reader reader = new StringReader(json);
    Class<Dummy> clazz = Dummy.class;
    Dummy dummy = new Dummy();

    // Mock Gson.fromJson(Reader, TypeToken) call inside fromJson(Reader, Class)
    Gson spyGson = Mockito.spy(gson);
    TypeToken<Dummy> typeToken = TypeToken.get(clazz);
    doReturn(dummy).when(spyGson).fromJson(reader, typeToken);

    // Mock Primitives.wrap(clazz).cast(object)
    try (MockedStatic<Primitives> primitivesStatic = Mockito.mockStatic(Primitives.class)) {
      primitivesStatic.when(() -> Primitives.wrap(clazz)).thenReturn(clazz);
      // cast returns dummy itself
      when(clazz.cast(dummy)).thenReturn(dummy);

      Dummy result = spyGson.fromJson(reader, clazz);
      assertSame(dummy, result);
    }
  }

  @Test
  void fromJson_withNullReader_throwsJsonSyntaxException() {
    Class<Dummy> clazz = Dummy.class;
    assertThrows(JsonSyntaxException.class, () -> gson.fromJson((Reader) null, clazz));
  }

  @Test
  void fromJson_withNullClass_throwsNullPointerException() {
    Reader reader = new StringReader("{}");
    assertThrows(NullPointerException.class, () -> gson.fromJson(reader, null));
  }

  // Dummy class for testing
  static class Dummy {
    String field;
  }
}
